mapper.select:
SELECT u.dept_id AS deptId, t.cycle_name AS cycleName, COUNT(r.id) AS totalCount, SUM(CASE WHEN r.status IN ('GRADED', 'CHEATED') THEN 1 ELSE 0 END) AS completedCount, ROUND(IFNULL(SUM(CASE WHEN r.status IN ('GRADED', 'CHEATED') THEN 1 ELSE 0 END) / COUNT(r.id) * 100, 0), 2) AS completionRate, ROUND(AVG(CASE WHEN r.status IN ('GRADED', 'CHEATED') THEN r.total_score ELSE NULL END), 2) AS averageScore, MAX(CASE WHEN r.status IN ('GRADED', 'CHEATED') THEN r.total_score ELSE NULL END) AS maxScore, MIN(CASE WHEN r.status IN ('GRADED', 'CHEATED') THEN r.total_score ELSE NULL END) AS minScore FROM perf_review r INNER JOIN perf_template t ON r.template_id = t.id LEFT JOIN sys_user u ON r.employee_id = u.id
AND t.cycle_name = #{cycleName}
GROUP BY u.dept_id, t.cycle_name ORDER BY t.cycle_name DESC, u.dept_id ASC
